# fix_strength_clean.ps1 — Full clean rewrite of strength.js
# Run from: C:\Users\Admin\panda-dashboard\

Write-Host "Writing clean strength.js..." -ForegroundColor Cyan

$b64 = ""

$bytes = [System.Convert]::FromBase64String($b64)
$outPath = Join-Path (Get-Location) "pages\strength.js"
[System.IO.File]::WriteAllBytes($outPath, $bytes)
Write-Host "Written: $((Get-Item $outPath).Length) bytes" -ForegroundColor Green

git add -f pages\strength.js
git commit -m "fix: clean strength.js rewrite - correct hook order, ResizeObserver, H1/H4/D1/W1"
git push
Write-Host "PUSHED! https://panda-dashboar.vercel.app/strength" -ForegroundColor Yellow